202:   /* Can't defer this, because it needs to happen before any
203:      later function definitions are processed.  */
204:   if (HAS_DECL_ASSEMBLER_NAME_P (decl)
205:       && DECL_ASSEMBLER_NAME_SET_P (decl)
206:       && DECL_REGISTER (decl))
207:     make_decl_rtl (decl);
