831: /* Propagate necessity using the operands of necessary statements.
832:    Process the uses on each statement in the worklist, and add all
833:    feeding statements which contribute to the calculation of this
834:    value to the worklist.
835: 
836:    In conservative mode, EL is NULL.  */
837: 
838: static void
839: propagate_necessity (bool aggressive)
840: {
841:   gimple *stmt;
842: 
843:   if (dump_file && (dump_flags & TDF_DETAILS))
844:     fprintf (dump_file, "\nProcessing worklist:\n");
845: 
846:   while (worklist.length () > 0)
847:     {
848:       /* Take STMT from worklist.  */
849:       stmt = worklist.pop ();
850: 
851:       if (dump_file && (dump_flags & TDF_DETAILS))
852: 	{
853: 	  fprintf (dump_file, "processing: ");
854: 	  print_gimple_stmt (dump_file, stmt, 0, TDF_SLIM);
855: 	  fprintf (dump_file, "\n");
856: 	}
857: 
858:       if (aggressive)
859: 	{
860: 	  /* Mark the last statement of the basic blocks on which the block
861: 	     containing STMT is control dependent, but only if we haven't
862: 	     already done so.  */
863: 	  basic_block bb = gimple_bb (stmt);
864: 	  if (bb != ENTRY_BLOCK_PTR_FOR_FN (cfun)
865: 	      && !bitmap_bit_p (visited_control_parents, bb->index))
866: 	    mark_control_dependent_edges_necessary (bb, false);
867: 	}
868: 
869:       if (gimple_code (stmt) == GIMPLE_PHI
870: 	  /* We do not process virtual PHI nodes nor do we track their
871: 	     necessity.  */
872: 	  && !virtual_operand_p (gimple_phi_result (stmt)))
873: 	{
874: 	  /* PHI nodes are somewhat special in that each PHI alternative has
875: 	     data and control dependencies.  All the statements feeding the
876: 	     PHI node's arguments are always necessary.  In aggressive mode,
877: 	     we also consider the control dependent edges leading to the
878: 	     predecessor block associated with each PHI alternative as
879: 	     necessary.  */
880: 	  gphi *phi = as_a <gphi *> (stmt);
881: 	  size_t k;
882: 
883: 	  for (k = 0; k < gimple_phi_num_args (stmt); k++)
884:             {
885: 	      tree arg = PHI_ARG_DEF (stmt, k);
886: 	      if (TREE_CODE (arg) == SSA_NAME)
887: 		mark_operand_necessary (arg);
888: 	    }
889: 
890: 	  /* For PHI operands it matters from where the control flow arrives
891: 	     to the BB.  Consider the following example:
892: 
893: 	     a=exp1;
894: 	     b=exp2;
895: 	     if (test)
896: 		;
897: 	     else
898: 		;
899: 	     c=PHI(a,b)
